6	export class Qwen2VLImageProcessor extends ImageProcessor {
7	    async _call(images, ...args) {
8	        const { pixel_values, original_sizes, reshaped_input_sizes } = await super._call(images, ...args);
9	
10	        let patches = pixel_values;
11	
12	        // @ts-ignore
13	        const { temporal_patch_size, merge_size, patch_size } = this.config;
14	        if (patches.dims[0] === 1) {
15	            // Equivalent to np.tile(patches, (self.temporal_patch_size, 1, 1, 1))
16	            patches = cat(Array.from({ length: temporal_patch_size }, () => patches), 0);
17	        }
18	
19	        const grid_t = patches.dims[0] / temporal_patch_size;
20	        const channel = patches.dims[1];
21	        const grid_h = Math.floor(patches.dims[2] / patch_size);
22	        const grid_w = Math.floor(patches.dims[3] / patch_size);
23	
24	        const flatten_patches = patches
25	            .view(
26	                grid_t,
27	                temporal_patch_size,
28	                channel,
29	                Math.floor(grid_h / merge_size),
30	                merge_size,
31	                patch_size,
32	                Math.floor(grid_w / merge_size),
33	                merge_size,
34	                patch_size,
35	            )
36	            .permute(0, 3, 6, 4, 7, 2, 1, 5, 8)
37	            .view(
38	                grid_t * grid_h * grid_w,
39	                channel * temporal_patch_size * patch_size * patch_size,
40	            )
41	
42	        const image_grid_thw = new Tensor('int64', [grid_t, grid_h, grid_w], [1, 3]);
43	
44	        return {
45	            pixel_values: flatten_patches,
46	            image_grid_thw,
47	            original_sizes,
48	            reshaped_input_sizes,
49	        }
50	    }
51	}
