## **4. Text Generation Patterns**

### **TextGenerationPipeline** (lines 984-1080)
Key pattern for generation-based pipelines:

```javascript
async _call(texts, generate_kwargs = {}) {
    let isBatched = false;
    let isChatInput = false;

    // Handle chat input
    let add_special_tokens = generate_kwargs.add_special_tokens
        ?? (this.tokenizer.add_bos_token || this.tokenizer.add_eos_token)
        ?? false;

    let inputs;
    if (typeof texts === 'string') {
        inputs = texts = [texts];
    } else if (Array.isArray(texts) && texts.every(x => typeof x === 'string')) {
        isBatched = true;
        inputs = texts;
    } else {
        if (isChat(texts)) {
            texts = [texts];
        } else if (Array.isArray(texts) && texts.every(isChat)) {
            isBatched = true;
        }
        isChatInput = true;

        // Apply chat template
        inputs = texts.map(x => 
            this.tokenizer.apply_chat_template(x, {
                tokenize: false,
                add_generation_prompt: true,
            })
        );
        add_special_tokens = false;
    }

    // Tokenize
    this.tokenizer.padding_side = 'left';
    const text_inputs = this.tokenizer(inputs, {
        add_special_tokens,
        padding: true,
        truncation: true,
    });

    // Generate
    const outputTokenIds = await this.model.generate({
        ...text_inputs,
        ...generate_kwargs
    });

    // Decode
    const decoded = this.tokenizer.batch_decode(outputTokenIds, {
        skip_special_tokens: true,
    });

    // Post-process (trim prompt if needed)
    let promptLengths;
    if (!return_full_text && text_inputs.input_ids.dims.at(-1) > 0) {
        promptLengths = this.tokenizer.batch_decode(text_inputs.input_ids, {
            skip_special_tokens: true,
        }).map(x => x.length);
    }

    const toReturn = Array.from({ length: texts.length }, _ => []);
    for (let i = 0; i < decoded.length; ++i) {
        const textIndex = Math.floor(i / outputTokenIds.dims[0] * texts.length);

        if (promptLengths) {
            decoded[i] = decoded[i].slice(promptLengths[textIndex]);
        }
        toReturn[textIndex].push({
            generated_text: isChatInput
                ? [
                    ...texts[textIndex],
                    { role: 'assistant', content: decoded[i] },
                  ]
                : decoded[i]
        });
    }
    return (!isBatched && toReturn.length === 1) ? toReturn[0] : toReturn;
}
```

### **Text2TextGenerationPipeline** (lines 730-789)
Seq2Seq generation pattern:

```javascript
async _call(texts, generate_kwargs = {}) {
    if (!Array.isArray(texts)) {
        texts = [texts];
    }

    // Add global prefix if present
    if (this.model.config.prefix) {
        texts = texts.map(x => this.model.config.prefix + x)
    }

    // Handle task-specific params
    const task_specific_params = this.model.config.task_specific_params;
    if (task_specific_params && task_specific_params[this.task]) {
        if (task_specific_params[this.task].prefix) {
            texts = texts.map(x => 
                task_specific_params[this.task].prefix + x
            )
        }
    }

    // Tokenize
    const tokenizer_options = {
        padding: true,
        truncation: true,
    }
    let inputs = this.tokenizer(texts, tokenizer_options);

    // Generate
    const outputTokenIds = await this.model.generate({ 
        ...inputs, 
        ...generate_kwargs 
    });

    // Decode
    return this.tokenizer.batch_decode(outputTokenIds, {
        skip_special_tokens: true,
    }).map(text => ({ [this._key]: text }));
}
```

