/**
 * Zero shot image classification pipeline. This pipeline predicts the class of
 * an image when you provide an image and a set of `candidate_labels`.
 *
 * **Example:** Zero shot image classification w/ `Xenova/clip-vit-base-patch32`.
 * ```javascript
 * const classifier = await pipeline('zero-shot-image-classification', 'Xenova/clip-vit-base-patch32');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/tiger.jpg';
 * const output = await classifier(url, ['tiger', 'horse', 'dog']);
 * // [
 * //   { score: 0.9993917942047119, label: 'tiger' },
 * //   { score: 0.0003519294841680676, label: 'horse' },
 * //   { score: 0.0002562698791734874, label: 'dog' }
 * // ]
 * ```
 */
export class ZeroShotImageClassificationPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ZeroShotImageClassificationPipelineType} */ (Pipeline)) {
    /**
     * Create a new ZeroShotImageClassificationPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ZeroShotImageClassificationPipelineCallback} */
    async _call(images, candidate_labels, {
        hypothesis_template = "This is a photo of {}"
    } = {}) {

        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        // Insert label into hypothesis template
        const texts = candidate_labels.map(
            x => hypothesis_template.replace('{}', x)
        );

        // Run tokenization
        const text_inputs = this.tokenizer(texts, {
            padding: this.model.config.model_type === 'siglip' ? 'max_length' : true,
            truncation: true,
        });

        // Run processor
        const { pixel_values } = await this.processor(preparedImages);

        // Run model with both text and pixel inputs
        const output = await this.model({ ...text_inputs, pixel_values });

        const function_to_apply =
            this.model.config.model_type === 'siglip'
                ? batch => batch.sigmoid().data
                : batch => softmax(batch.data);

        // Compare each image with each candidate label
        const toReturn = [];
        for (const batch of output.logits_per_image) {
            // Compute softmax per image
            const probs = function_to_apply(batch);

            const result = [...probs].map((x, i) => ({
                score: x,
                label: candidate_labels[i]
            }));
            result.sort((a, b) => b.score - a.score); // sort by score in descending order
            toReturn.push(result);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}
```

**Key Implementation Details:**
- **Class Name:** `ZeroShotImageClassificationPipeline`
- **Constructor Parameters:** `TextImagePipelineConstructorArgs` (task, model, tokenizer, processor)
- **_call() Signature:** `async _call(images, candidate_labels, { hypothesis_template = "This is a photo of {}" } = {})`
- **Inputs:**
  - `images` - ImagePipelineInputs (single or batch)
  - `candidate_labels` - array of label strings
  - `hypothesis_template` - optional template string
- **Output Type:** `{ score: number, label: string }[][]` or `[]` (sorted by score descending)
- **Processing Flow:**
  1. Prepare images via `prepareImages()`
  2. Create text templates by inserting labels into hypothesis template
  3. `this.tokenizer(texts, {...})` - tokenizes label hypotheses
  4. `this.processor(preparedImages)` - processes images to pixel_values
  5. `this.model({ ...text_inputs, pixel_values })` - **joint model forward pass with both modalities**
  6. Extracts `logits_per_image` from output and applies softmax/sigmoid
  7. Maps scores back to labels and sorts by score
- **Generate Call:** Does NOT use generate(); uses direct model forward pass instead

