 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput|ImageTextToTextOutput[]>} An object (or array of objects) containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-text-to-text pipeline using `AutoModelForImageTextToText`. This pipeline generates text
 * conditioned on an image and a text prompt, enabling visual question answering, image captioning
 * with instructions, and other vision-language tasks.
 *
 * **Example:** Generate text from an image and a text prompt w/ `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const messages = [
 *   { role: 'user', content: [{ type: 'image' }, { type: 'text', text: 'What is in this image?' }] }
 * ];
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await pipe(url, messages);
 * // [{ generated_text: 'Two cats are lying on a couch.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, texts, generate_kwargs = {}) {

        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        // Handle chat messages format by applying the model's chat template
        if (isChat(texts)) {
            texts = this.tokenizer.apply_chat_template(
                /** @type {import('./tokenizers.js').Message[]} */ (texts),
                { tokenize: false, add_generation_prompt: true },
            );
        }

        // Use text-first convention (matches SmolVLM/Idefics3 and Qwen2-VL processors)
        const inputs = await this.processor(texts, preparedImages);
        const outputIds = await this.model.generate({ ...inputs, ...generate_kwargs });

        const decoded = this.tokenizer.batch_decode(
            /** @type {Tensor} */ (outputIds),
            { skip_special_tokens: true },
        ).map(x => ({ generated_text: x.trim() }));

        return isBatched ? [decoded] : decoded;
    }
}

/**
 * @typedef {Object} ImageClassificationSingle
 * @property {string} label The label identified by the model.
 * @property {number} score The score attributed by the model for that label.
 * @typedef {ImageClassificationSingle[]} ImageClassificationOutput
 *
 * @typedef {Object} ImageClassificationPipelineOptions Parameters specific to image classification pipelines.
 * @property {number} [top_k=1] The number of top labels that will be returned by the pipeline.
